package com.bank.ea.config;
import com.bank.ea.domain.Project; import com.bank.ea.repo.*; import java.util.List; import org.springframework.boot.CommandLineRunner; import org.springframework.core.annotation.Order; import org.springframework.context.annotation.*;
@Configuration public class ProjectDataConfig {
 @Bean @Order(2) CommandLineRunner mpmProject(ProjectRepository projects,CatalogRepository items){return args->{Project p=projects.findByCode("MPM-CRM").orElseGet(()->{Project x=new Project();x.setName("MPM Property Leasing CRM");x.setCode("MPM-CRM");x.setStage(Project.Stage.UNDER_REVIEW);x.setSponsor("MPM Executive Sponsor");x.setBusinessOwner("Leasing Operations");x.setLeadArchitect("CRM Solution Architect");x.setOverallRisk("High");x.setStartDate("2026-07-01");x.setTargetDate("2026-12-15");x.setProblemStatement("Create a controlled Dynamics 365 leasing platform and a single view of properties, units, prospects, tenants, offers, leases and renewals.");x.setApprovalAuthority("Solution Architect review; Security and Data Architecture endorsement; Architecture Review Board final approval; EA Head approves exceptions.");x.setMandatoryInformation("Business case; scope; capability map; solution context; data model; integration catalogue; security design; NFRs; migration plan; DR plan; test strategy; support model.");x.setExistingTools("Jira for delivery; SharePoint for controlled documents; ServiceNow for CMDB and change; Dynamics 365/Dataverse for CRM; integration with LeanIX if adopted.");x.setSsoRequirements("Microsoft Entra ID SSO with MFA and conditional access; service principals for non-interactive integrations.");x.setSecurityRequirements("Least privilege; segregated admin roles; field security; encryption; Dataverse auditing; DLP policies; periodic access recertification.");x.setHostingRequirements("Bank-approved Microsoft cloud tenant, UAE data-residency assessment, managed environments and controlled ALM pipelines.");x.setRetentionRequirements("Retention schedule approved by Legal and Records Management; tenant documents retained according to contract and regulatory policy; defensible deletion.");x.setExecutiveReports("Portfolio status; approval stage; critical risks; overdue conditions; integration readiness; security findings; decisions required.");x.setAuditEvidence("Review submissions; reviewer comments; approvals; architecture decisions; exceptions; risk acceptance; test evidence; deployment approvals.");x.setRepositoryOwner("Enterprise Architecture");x.setRepositoryMaintainer("EA Governance Office / assigned Solution Architect");return projects.save(x);});
  List<String> names=List.of("MPM Leasing CRM","Property & Unit Management","Tenant 360","Lease Lifecycle Management","Microsoft Dynamics 365 Sales","Microsoft Dataverse","Power Automate","Power Pages","Property and Unit Data Model","Lease Approval Workflow","Dynamics Security Model","Property availability synchronisation","Duplicate customer and tenant records","Excessive Dynamics privileges","Property Inventory Integration","Finance and Contract Integration","Document Management Integration","Email and SMS Notifications");
  names.forEach(n->items.findByName(n).ifPresent(i->{if(i.getProject()==null){i.setProject(p);items.save(i);}}));
 };}
}
